#include<bits/stdc++.h>
using namespace std;

int a[100005];

int main()
{
	int t;
	cin >> t;
	while(t--)
	{
		int n, sum = 0;
		cin >> n;
		for(int i = 1; i <= n; i++)
		{
			cin >> a[i];
			sum += a[i];
		}
		for(int i = n; i >= 1; i--)
		{
			if(sum % i != 0) continue;
			int k = sum / i, tmp = 0;bool flag = 1;
			for(int i = 1; i <= n; i++)
			{
				tmp += a[i];
				if(tmp > k)
				{
					flag = 0;
					break;
				}
				if(tmp == k) tmp = 0;
			}
			if(flag)
			{
				cout << n - i << endl;
				break;
			}
		}
	}
}
